import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class Solution {
    public static long[][] solve(long[][] grid, long x, long y, long k) {
        int m = grid.length;
        int n = grid[0].length;

        List<long[]> submatrix = new ArrayList<>();

        for (int i = 0; i < k; i++) {
            long[] row = new long[k];
            for (int j = 0; j < k; j++) {
                row[j] = grid[(int)x + i][(int)y + j];
            }
            submatrix.add(row);
        }

        Collections.reverse(submatrix);

        for (int i = 0; i < k; i++) {
            long[] flippedRow = submatrix.get(i);
            for (int j = 0; j < k; j++) {
                grid[(int)x + i][(int)y + j] = flippedRow[j];
            }
        }

        return grid;
    }
}
